import{_ as r}from"./nyalra_kb-7135827b.js";import{_ as d}from"./nyalra_no_mono-8344e451.js";import{_ as p,W as c,X as s,Y as _,Z as e,$ as t,a1 as o,a2 as i,a0 as m,C as a}from"./framework-91490e6a.js";const f={},u=e("figure",null,[e("img",{src:r,alt:"",tabindex:"0",loading:"lazy"}),e("figcaption")],-1),h={href:"https://tree-novel.com/works/episode/a823040a7447cb17baeea1bf48ea871c.html",target:"_blank",rel:"noopener noreferrer"},k=e("p",null,"这是在互联网中栖息的不可思议生物·Nyalra于深夜写下的有关互联网、独居生活以及除此之外的事物的图文随笔。",-1),b=m('<hr><p>经常有人问我：「我总是不能遵守ddl（Deadline），该怎么办？」。我懂这种感觉。努力奋斗，怀抱着追求憧憬的梦想而全力以赴的觉悟。但是……尽管如此，还是无法守住ddl！难道是我缺乏干劲！？难道其他人对时间的管理更加严格吗！？随着时间的推移，焦虑感越来越强烈……</p><p>但请放心。不，不能因为这样的事情就放心。我和我周围的作家们都在竭尽全力地对待ddl。当然，我们都希望尽可能地准时完成工作并履行作为专业人士的责任，但是我们还是会在ddl临近时才开始动手。我相信这是大多数人的情况。人们在ddl来临之前很难充满动力。</p><p>这并不是逃避，倒不如说是一种「学习」。假设还有一个月就要到ddl，如果你能够逐渐推进稿件，那就完全没有问题。但即便如此，前三个星期还是不会有动力。或许会在脑海中意识到稿件的事情，模糊地想象要写些什么，但直到ddl只剩几天的时候才开始动笔。我这样的人绝对会这样。无论反省多少次说「这次我要逐步推进，留出余裕！」，最终都会变成临近ddl时才开始动手。</p><p>但是，一直过分依赖了「全盛期的写作速度」。因为过去可以熬夜写完，所以就松懈、自满，没有考虑到人的体力会随年龄而下降。那是因为年轻时有激情才能做到的。如今，随着睡眠时间的减少，表现也直接下降。很遗憾，什么都不做体力就过剩的20多岁已经过去了。真是令人悲伤。</p><p>因此，我已经不再天真地相信自己能够拥有对ddl有余裕的能力了。所以，我会在与客户协商时决胜负。在像这样的专栏连载中，我会在开始之前预先准备好很多稿件，或者请求「把ddl写得早一点」，在实际上还有大量余裕的交稿日前提前交稿。对不起！但是，我真的无法直接地提交稿件……</p><p>这样的无理请求之所以能够通过，是因为交付物的质量和话题性还算可以。但这只是因为仅剩的一点「年轻」所致。随着时间的推移，它会逐渐消耗殆尽，我们需要意识到自己正在失去价值。</p><p>这样一来，如果我变成了「连ddl都无法遵守，没有任何实力的垃圾」，那么工作量肯定会减少。如果有一天逆转成了「我的商品价值&lt;懒惰的心态」，那就完全完蛋了。可能会变成那种才能枯竭不被认可，却转嫁责任说「最近的出版社都怎么了？」的男人。我不想成为那种令人难堪的中年人。</p><p>为了不走上这样可悲的结局，我只能全力以赴地写作。即使是这篇稿件，虽然截止日期是周日晚上，但我在周一早上才提交。「反正编辑大概中午才会起床，所以在交稿日的第二天早上之前都是安全的！」这是作家们常常使用的借口。这样做的话，交稿的时间会越来越晚！要反省！对不起。下次会在晚上赶上的……。</p><hr><p><img src="'+d+'" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/c512133ff8cba0ff4ab055ed60e57bc5.jpg" alt="" loading="lazy"></p><blockquote><p>本周的にゃるら的物品：</p><p>【黑多拉的软胶玩具】在众多化学工厂生产的黑多拉软胶怪兽玩具中，这款是我最喜欢的，充满震撼力。毕竟怪兽软胶玩具简单而巨大才好！颜色方面，有这款原创的多彩色和接近原作的黑色可供选择，我在纠结中选择了这个。每一种鲜艳的、迷幻的颜色都蕴含着对人类的怨恨。</p></blockquote>',12);function g(x,y){const l=a("ExternalLinkIcon"),n=a("RouterLink");return c(),s("div",null,[_(" more "),u,e("p",null,[t("原文链接："),e("a",h,[t("第18回／キミは締め切りをちゃんと守れる人になれるか？"),o(l)])]),e("blockquote",null,[k,e("p",null,[o(n,{to:"/posts/Translate/nyalra_kb_17.html"},{default:i(()=>[t("【奈亚拉面壁自语】第17回｜怀抱悲伤独自失落【230314】")]),_:1})])]),b])}const C=p(f,[["render",g],["__file","nyalra_kb_18.html.vue"]]);export{C as default};
